using System.ComponentModel;
using System.Net;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var noteService = new NoteService();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(noteService.AddNote),
    AIFunctionFactory.Create(noteService.GetNotes),
};

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An agent that researches topics by searching the web and taking notes.",
    instructions: """
        You are a thorough research agent. When given a topic:
        1. Search the web for multiple aspects of the topic using the SearchWeb tool
        2. Take notes on the most important findings using the AddNote tool
        3. Review your collected notes using the GetNotes tool
        4. Provide a well-organized summary of your key findings

        Always perform at least 2-3 different searches before summarizing.
        Take notes on key facts, statistics, and insights as you research.
        """,
    tools: tools);

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic thoroughly and provide a comprehensive summary:\n\n{topic}",
    session: null,
    options: runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine();

// --- Tool implementations ---

[Description("Search the web for information on a query and return relevant snippets")]
static async Task<string> SearchWeb(
    [Description("The search query to look up")] string query)
{
    Console.WriteLine($"  [search] {query}");

    using var httpClient = new HttpClient();
    httpClient.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var encoded = Uri.EscapeDataString(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    try
    {
        var html = await httpClient.GetStringAsync(url);

        var results = new List<string>();
        const string marker = "result__snippet";
        var idx = 0;

        while (results.Count < 5 &&
               (idx = html.IndexOf(marker, idx, StringComparison.Ordinal)) >= 0)
        {
            var tagEnd = html.IndexOf('>', idx) + 1;
            var contentEnd = html.IndexOf('<', tagEnd);
            if (tagEnd > 0 && contentEnd > tagEnd)
            {
                var snippet = WebUtility.HtmlDecode(html[tagEnd..contentEnd].Trim());
                if (!string.IsNullOrWhiteSpace(snippet))
                    results.Add(snippet);
            }

            idx = contentEnd > 0 ? contentEnd : idx + marker.Length;
        }

        return results.Count > 0
            ? string.Join("\n\n", results.Select((r, i) => $"{i + 1}. {r}"))
            : "No results found for this query.";
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}";
    }
}

// --- Note service ---

sealed class NoteService
{
    private readonly List<string> _notes = [];

    [Description("Save a research note about a key finding for later reference")]
    public string AddNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [note #{_notes.Count} saved]");
        return $"Note #{_notes.Count} saved successfully.";
    }

    [Description("Retrieve all saved research notes collected so far")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        return string.Join("\n",
            _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

